const body = $input.first().json.body ?? $input.first().json;
const text = (body?.text ?? '').trim();
if (!text) throw new Error('Campo text es requerido');
return [{ json: { text: 'Entrada: ' + JSON.stringify(text) + '\nSalida:' } }];

const output = ($input.first().json.output ?? '').trim();

let parsed;
try {
  const match = output.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : {};
} catch {
  parsed = {};
}

const VALID = ['CALENDAR', 'QUOTE', 'INVOICE', 'PURCHASE'];
const enhancedText = typeof parsed.texto_mejorado === 'string' && parsed.texto_mejorado.trim()
  ? parsed.texto_mejorado.trim()
  : '';

if (!enhancedText) throw new Error('El agente devolvió una respuesta inválida: ' + output);

return [{
  json: {
    enhanced_text: enhancedText,
    processed_by: 'backend',
    actions: Array.isArray(parsed.acciones)
      ? parsed.acciones.filter(a => VALID.includes(a))
      : [],
    redirects: Array.isArray(parsed.redirects)
      ? parsed.redirects.filter(r => typeof r === 'string')
      : []
  }
}];
